#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int solve(string& s) {
        int maxDepth = 0, cur = 0;
        for (char ch : s) {
            if (ch == '(') {
                ++cur;
                if (cur > maxDepth) maxDepth = cur;
            } else if (ch == ')') {
                --cur;
            }
        }
        return maxDepth;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    string s;
    if (!(cin >> s)) return 0;
    Solution sol;
    int ans = sol.solve(s);
    cout << ans << "\n";
    return 0;
}
